const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const CORE = path.join(PROJECT, 'src-tauri/src/core');

const readFile = (p) => {
  try { return fs.readFileSync(p, 'utf8'); } catch { return '// FILE NOT FOUND'; }
};

const context = {
  solver: readFile(path.join(CORE, 'solver.rs')),
  green: readFile(path.join(CORE, 'green.rs')),
  impedance: readFile(path.join(CORE, 'impedance.rs')),
  port: readFile(path.join(CORE, 'port.rs')),
  linalg: readFile(path.join(CORE, 'linalg.rs')),
  mom_surface: readFile(path.join(CORE, 'mom_surface.rs')),
  mesher: readFile(path.join(CORE, 'mesher.rs')),
  rwg: readFile(path.join(CORE, 'rwg.rs')),
  nf2ff: readFile(path.join(CORE, 'nf2ff.rs')),
  import_stl: readFile(path.join(CORE, 'import_stl.rs')),
  import_nec: readFile(path.join(CORE, 'import_nec.rs')),
  bridge: readFile(path.join(PROJECT, 'src-tauri/src/bridge.rs')),
  fdtd_runner: readFile(path.join(PROJECT, 'python/antenna_ml/fdtd/runner.py')),
  cargo_toml: readFile(path.join(PROJECT, 'src-tauri/Cargo.toml')),
};

return [{ json: { context } }];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const CORE = path.join(PROJECT, 'src-tauri/src/core');

const agents = ['Gen Rust Benchmarks', 'Gen Python Benchmarks', 'Gen Integration Tests'];
const fileRegex = /<file path="([^"]+)">\n?([\s\S]*?)<\/file>/g;
const results = {};
let filesWritten = 0;

for (const agentName of agents) {
  try {
    const output = $(agentName).item.json.output || '';
    let match;
    const regex = new RegExp(fileRegex.source, fileRegex.flags);
    while ((match = regex.exec(output)) !== null) {
      const fullPath = path.join(PROJECT, match[1]);
      const dir = path.dirname(fullPath);
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
      fs.writeFileSync(fullPath, match[2].trim());
      results[match[1]] = `WRITTEN (${match[2].length} chars)`;
      filesWritten++;
    }
  } catch (e) {
    results[agentName] = `ERROR: ${e.message}`;
  }
}

// Update mod.rs
const modPath = path.join(CORE, 'mod.rs');
let modContent = fs.readFileSync(modPath, 'utf8');
if (!modContent.includes('benchmark_antennas')) {
  modContent += '\n#[cfg(test)]\npub mod benchmark_antennas;\n';
  fs.writeFileSync(modPath, modContent);
}

// Run Rust tests
let rustTests = '';
try {
  rustTests = execSync('cd src-tauri && cargo test 2>&1', { cwd: PROJECT, timeout: 600000 }).toString();
} catch (e) {
  rustTests = e.stdout?.toString() || e.message;
}

// Run Python tests
let pythonTests = '';
try {
  pythonTests = execSync('cd python && python -m pytest tests/test_benchmark.py -v 2>&1', { cwd: PROJECT, timeout: 300000 }).toString();
} catch (e) {
  pythonTests = e.stdout?.toString() || e.message;
}

return [{ json: { filesWritten, results, rustTests, pythonTests } }];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const prev = $('Write + Run Tests').item.json;
const needsFix = prev.rustTests.includes('FAILED') || prev.pythonTests.includes('FAILED');
let fixResult = 'No fix needed';

if (needsFix) {
  const output = $('Self-Fix Agent').item.json.output || '';
  const fileRegex = /<file path="([^"]+)">\n?([\s\S]*?)<\/file>/g;
  let match;
  while ((match = fileRegex.exec(output)) !== null) {
    const fullPath = path.join(PROJECT, match[1]);
    const dir = path.dirname(fullPath);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(fullPath, match[2].trim());
  }
  fixResult = 'Fixes applied';
}

let gitResult = '';
try {
  execSync('git add -A', { cwd: PROJECT });
  execSync('git commit -m "test: add EM solver benchmarks and integration tests\n\nRust: dipole/monopole benchmarks, convergence study, matrix properties.\nPython: FDTD vs MoM comparison, PML absorption, grid convergence.\nFrontend: file import, solver flow, app integration tests."', { cwd: PROJECT });
  execSync('git push origin main', { cwd: PROJECT });
  gitResult = 'Committed and pushed';
} catch (e) {
  gitResult = 'Git: ' + e.message;
}

return [{ json: { ...prev, fixResult, gitResult, phase: 'tests', status: 'complete' } }];
